/*
MERGE ENGINE OVERVIEW

Inputs:
- xWFData       : Target/master XML (loaded into targetDoc)
- dParentDocument : Source XML (loaded into sourceDoc, rooted at <Document>)
- dMergeRules   : Rules table, each <Row> defines one merge rule

Common per-row fields:
- Condition   : XPath boolean expression evaluated against targetDoc.
                If false, the rule is skipped.
- Action      : One of [Add, AddWithNameChange, SetValue, UpsertTree, ReplaceTree, Delete].
- SourceNode  : XPath in sourceDoc (under <Document>) selecting the source node.
- TargetNode  : XPath in targetDoc. Meaning depends on Action (see below).
- TargetParent: XPath in targetDoc. Used only by UpsertTree inserts (ignored for most others).
- InsertBefore: XPath in targetDoc. Optional anchor for ordered inserts (UpsertTree, AddWithNameChange).

Action semantics:

1) Add
   - SourceNode  : subtree to copy.
   - TargetNode  : XPath to the *parent* element in targetDoc.
   - Behavior    : Imports the entire source subtree and appends it as a new child of TargetNode.
   - TargetParent / InsertBefore: ignored.

2) AddWithNameChange
   - SourceNode  : node whose InnerText will be copied.
   - TargetNode  : full XPath to the *new element*, e.g. //DocumentData/Supplier_Name.
                   Parent XPath = everything before the last '/', element name = last segment.
   - Behavior    : Requires the parent node to exist. Creates a new child element under that parent
                   with the derived name and sets its InnerText from SourceNode.
   - InsertBefore: Optional. If provided, the new element is inserted before this anchor under the same parent.
   - TargetParent: ignored for this action (parent is derived from TargetNode).

3) SetValue
   - SourceNode  : node whose InnerText will be copied.
   - TargetNode  : XPath to an *existing* single node in targetDoc.
   - Behavior    : If both SourceNode and TargetNode exist, sets TargetNode.InnerText = SourceNode.InnerText.
                   If either is missing, the rule is skipped (no create).
   - TargetParent / InsertBefore: ignored.

4) UpsertTree
   - SourceNode   : subtree to copy.
   - TargetNode   : XPath to the node to replace if it exists.
   - TargetParent : Required when TargetNode does not exist; XPath to the parent for insert.
   - InsertBefore : Optional anchor under TargetParent. If present, insert before; else append.
   - Behavior     :
       - If TargetNode matches exactly 1 node, replace that node (parent.ReplaceChild).
       - If TargetNode matches 0 nodes, import the subtree and insert under TargetParent (before InsertBefore if given).
       - If TargetNode matches >1 nodes → error.

5) ReplaceTree
   - SourceNode  : subtree to copy.
   - TargetNode  : XPath to the node to replace.
   - Behavior    : If TargetNode exists, replace that node with the imported subtree.
                   If TargetNode is missing, the rule is skipped.
   - TargetParent / InsertBefore: ignored.

6) Delete
   - TargetNode  : XPath to the node to delete. If blank, SourceNode is used as the delete XPath.
   - Behavior    : If a single matching node is found in targetDoc, removes it from its parent.
                   If no match, the rule is skipped.
   - TargetParent / InsertBefore: ignored.

General notes:
- All XPaths in SourceNode and TargetNode are evaluated against sourceDoc and targetDoc respectively.
- SelectSingleOrError enforces 0, 1, or >1 match rules depending on skipIfMissing.
- Conditions are evaluated against the current targetDoc before applying the rule.
*/
//
// TARGET (master) = xWFData
//
var xWFData = _context.XmlVariables["xWFData"].GetXmlNode("//*").OuterXml;

//
// SOURCE is the output of the DocGen Step
//
var xMergeSourceRaw = _context.XmlVariables["dParentDocument"].GetXmlNode("//*").OuterXml;

//
// MERGE RULES (CSV -> Rows/Row)
//
XmlNodeList mergeRulesList = _context.XmlVariables["dMergeRules"].GetXmlNodes("//Row");

var targetDoc = new XmlDocument { PreserveWhitespace = true };
targetDoc.LoadXml(xWFData);

var sourceRawDoc = new XmlDocument { PreserveWhitespace = true };
sourceRawDoc.LoadXml(xMergeSourceRaw);

XmlNode sourceDocumentData = sourceRawDoc.SelectSingleNode("//Document");
if (sourceDocumentData == null)
    throw new Exception("Source XML does not contain Document Node.");

var sourceDoc = new XmlDocument { PreserveWhitespace = true };
sourceDoc.LoadXml(sourceDocumentData.OuterXml);

string GetRowValue(XmlNode row, string nodeName)
{
    XmlNode n = row.SelectSingleNode(nodeName);
    return n == null ? "" : (n.InnerText ?? "").Trim();
}

XmlNode SelectSingleOrError(XmlDocument doc, string xpath, string label, bool skipIfMissing)
{
    if (string.IsNullOrWhiteSpace(xpath))
        throw new Exception(label + " XPath is blank.");

    XmlNodeList nodes = doc.SelectNodes(xpath);
    int count = (nodes == null) ? 0 : nodes.Count;

    if (count == 0)
    {
        if (skipIfMissing) return null;
        throw new Exception(label + " XPath matched 0 nodes: " + xpath);
    }

    if (count > 1)
        throw new Exception(label + " XPath matched " + count + " nodes (must be exactly 1): " + xpath);

    return nodes[0];
}

XmlNode SelectZeroOrOneOrError(XmlDocument doc, string xpath, string label)
{
    if (string.IsNullOrWhiteSpace(xpath))
        throw new Exception(label + " XPath is blank.");

    XmlNodeList nodes = doc.SelectNodes(xpath);
    int count = (nodes == null) ? 0 : nodes.Count;

    if (count == 0) return null;

    if (count > 1)
        throw new Exception(label + " XPath matched " + count + " nodes (must be 0 or 1): " + xpath);

    return nodes[0];
}

bool EvaluateCondition(string condition)
{
    if (string.IsNullOrWhiteSpace(condition)) return true;
    var nav = targetDoc.CreateNavigator();
    var expr = System.Xml.XPath.XPathExpression.Compile(condition.Trim());
    var result = nav.Evaluate(expr);
    if (result is bool b) return b;
    throw new Exception("Condition must evaluate to a boolean.");
}

// =====================
// Merge Execution (top-down)
// =====================
foreach (XmlNode rule in mergeRulesList)
{
    string condition = GetRowValue(rule, "Condition");
    if (!EvaluateCondition(condition))
        continue;

    string actionRaw = GetRowValue(rule, "Action");
    string sourceXPath = GetRowValue(rule, "SourceNode");
    string targetXPath = GetRowValue(rule, "TargetNode");
    if (!string.IsNullOrWhiteSpace(targetXPath))
        targetXPath = targetXPath.Trim();

    if (string.IsNullOrWhiteSpace(actionRaw))
        throw new Exception("Merge rule Action is blank.");

    string action = actionRaw.Trim();

    // Backward-compatible aliases
    if (action.Equals("UpdateTree", StringComparison.OrdinalIgnoreCase)) action = "ReplaceTree";
    if (action.Equals("Update", StringComparison.OrdinalIgnoreCase)) action = "ReplaceTree";

    if (action.Equals("Add", StringComparison.OrdinalIgnoreCase))
    {
        // Source missing -> skip
        XmlNode src = SelectSingleOrError(sourceDoc, sourceXPath, "SourceNode", skipIfMissing: true);
        if (src == null) continue;

        // Target parent must exist (unique)
        XmlNode tgtParent = SelectSingleOrError(targetDoc, targetXPath, "TargetNode", skipIfMissing: false);

        XmlNode imported = targetDoc.ImportNode(src, true);
        tgtParent.AppendChild(imported); // add to end
    }
    else if (action.Equals("AddWithNameChange", StringComparison.OrdinalIgnoreCase))
    {
        // Source missing -> skip
        XmlNode src = SelectSingleOrError(sourceDoc, sourceXPath, "SourceNode", skipIfMissing: true);
        if (src == null) continue;

        // For AddWithNameChange, TargetNode is the full path to the new element,
        // e.g. //DocumentData/Supplier_Name
        if (string.IsNullOrWhiteSpace(targetXPath))
            throw new Exception("AddWithNameChange requires TargetNode (full XPath).");

        // Find parent path and element name
        var lastSlash = targetXPath.LastIndexOf('/');
        if (lastSlash <= 0 || lastSlash == targetXPath.Length - 1)
            throw new Exception("AddWithNameChange TargetNode must include a parent path and element name: " + targetXPath);

        string parentXPath = targetXPath.Substring(0, lastSlash);
        string elementName = targetXPath.Substring(lastSlash + 1);

        // Parent must exist
        XmlNode tgtParent = SelectSingleOrError(targetDoc, parentXPath, "TargetNode parent", skipIfMissing: false);

        // Create new element with desired name and copy text from source
        XmlElement elem = targetDoc.CreateElement(elementName);
        elem.InnerText = src.InnerText;

        // Optional InsertBefore still respected if you want it
        string insertBeforeXPath = GetRowValue(rule, "InsertBefore");
        if (!string.IsNullOrWhiteSpace(insertBeforeXPath))
        {
            XmlNode anchor = SelectSingleOrError(targetDoc, insertBeforeXPath, "InsertBefore", skipIfMissing: false);
            if (!ReferenceEquals(anchor.ParentNode, tgtParent))
                throw new Exception("InsertBefore node is not a child of TargetNode parent.");

            tgtParent.InsertBefore(elem, anchor);
        }
        else
        {
            tgtParent.AppendChild(elem);
        }
    }
    else if (action.Equals("SetValue", StringComparison.OrdinalIgnoreCase))
    {
        // Source missing -> skip
        XmlNode src = SelectSingleOrError(sourceDoc, sourceXPath, "SourceNode", skipIfMissing: true);
        if (src == null) continue;

        // Target missing -> skip
        XmlNode tgt = SelectSingleOrError(targetDoc, targetXPath, "TargetNode", skipIfMissing: true);
        if (tgt == null) continue;

        tgt.InnerText = src.InnerText;
    }
    else if (action.Equals("UpsertTree", StringComparison.OrdinalIgnoreCase))
    {
        // Source missing -> skip
        XmlNode src = SelectSingleOrError(sourceDoc, sourceXPath, "SourceNode", skipIfMissing: true);
        if (src == null) continue;

        XmlNode existing = SelectZeroOrOneOrError(targetDoc, targetXPath, "TargetNode");
        XmlNode imported = targetDoc.ImportNode(src, true);

        if (existing != null)
        {
            XmlNode parent = existing.ParentNode;
            if (parent == null)
                throw new Exception("TargetNode has no parent; cannot UpsertTree replace.");

            parent.ReplaceChild(imported, existing);
        }
        else
        {
            string targetParentXPath = GetRowValue(rule, "TargetParent");
            if (string.IsNullOrWhiteSpace(targetParentXPath))
                throw new Exception("UpsertTree insert requires TargetParent when TargetNode does not exist.");

            XmlNode tgtParent = SelectSingleOrError(targetDoc, targetParentXPath, "TargetParent", skipIfMissing: false);

            string insertBeforeXPath = GetRowValue(rule, "InsertBefore");
            if (!string.IsNullOrWhiteSpace(insertBeforeXPath))
            {
                XmlNode anchor = SelectSingleOrError(targetDoc, insertBeforeXPath, "InsertBefore", skipIfMissing: false);
                if (!ReferenceEquals(anchor.ParentNode, tgtParent))
                    throw new Exception("InsertBefore node is not a child of TargetParent.");

                tgtParent.InsertBefore(imported, anchor);
            }
            else
            {
                tgtParent.AppendChild(imported);
            }
        }
    }
    else if (action.Equals("ReplaceTree", StringComparison.OrdinalIgnoreCase))
    {
        // Source missing -> skip
        XmlNode src = SelectSingleOrError(sourceDoc, sourceXPath, "SourceNode", skipIfMissing: true);
        if (src == null) continue;

        // Target missing -> skip (only Add creates)
        XmlNode tgt = SelectSingleOrError(targetDoc, targetXPath, "TargetNode", skipIfMissing: true);
        if (tgt == null) continue;

        XmlNode imported = targetDoc.ImportNode(src, true);

        XmlNode parent = tgt.ParentNode;
        if (parent == null)
            throw new Exception("TargetNode has no parent; cannot ReplaceTree.");

        parent.ReplaceChild(imported, tgt);
    }
    else if (action.Equals("Delete", StringComparison.OrdinalIgnoreCase))
    {
        // Delete uses TargetNode if provided, else SourceNode as the path-to-delete in target
        string deleteXPath = !string.IsNullOrWhiteSpace(targetXPath) ? targetXPath : sourceXPath;

        // Missing -> skip
        XmlNode tgt = SelectSingleOrError(targetDoc, deleteXPath, "Delete XPath", skipIfMissing: true);
        if (tgt == null) continue;

        XmlNode parent = tgt.ParentNode;
        if (parent != null)
            parent.RemoveChild(tgt);
    }
    else
    {
        throw new Exception("Unsupported merge Action: " + actionRaw);
    }
}

// Return merged xWFData XML
return targetDoc.OuterXml;

